final_template:
AWSTemplateFormatVersion: '2010-09-09'
Description: 'CloudWatch Dashboard for NAT Gateway VPC Flow Logs Monitoring'

Parameters:
  DashboardName:
    Type: String
    Default: 'NATGatewayFlowLogsDashboard'
    Description: Unique name for the CloudWatch Dashboard
  LogGroupName:
    Type: String
    Default: '/aws/vpc/flowlogs/default'
    Description: Name or ARN of the VPC Flow Logs CloudWatch Logs log group

Resources:
  NATGatewayFlowLogsDashboard:
    Type: AWS::CloudWatch::Dashboard
    Properties:
      DashboardName: !Sub '${DashboardName}'
      DashboardBody:
        Fn::Sub: |
          {
            "widgets": [
              {
                "type": "log",
                "properties": {
                  "title": "Top 10 Source IPs by Outbound Bytes",
                  "logGroupNames": [ "${LogGroupName}" ],
                  "view": "table",
                  "timeRange": {
                    "Relative": "P7D"
                  },
                  "region": "${AWS::Region}",
                  "query": {
                    "SourceId": "1",
                    "QueryString": "filter interfaceId like /eni-/ and action = \"ACCEPT\" and flowDirection = \"out\" | stats sum(bytes) as totalBytes by bin(1h), srcAddr | sort totalBytes desc | limit 10"
                  }
                },
                "position": [0, 24, 12, 6]
              },
              {
                "type": "log",
                "properties": {
                  "title": "Top 10 Source IPs by Outbound Packets",
                  "logGroupNames": [ "${LogGroupName}" ],
                  "view": "table",
                  "timeRange": {
                    "Relative": "P7D"
                  },
                  "region": "${AWS::Region}",
                  "query": {
                    "SourceId": "1",
                    "QueryString": "filter interfaceId like /eni-/ and action = \"ACCEPT\" and flowDirection = \"out\" | stats sum(packets) as totalPackets by bin(1h), srcAddr | sort totalPackets desc | limit 10"
                  }
                },
                "position": [12, 24, 12, 6]
              },
              {
                "type": "log",
                "properties": {
                  "title": "Top 10 Source IPs by Rejected Connections",
                  "logGroupNames": [ "${LogGroupName}" ],
                  "view": "table",
                  "timeRange": {
                    "Relative": "P7D"
                  },
                  "region": "${AWS::Region}",
                  "query": {
                    "SourceId": "1",
                    "QueryString": "filter interfaceId like /eni-/ and action = \"REJECT\" | stats count() as rejects by bin(1h), srcAddr | sort rejects desc | limit 10"
                  }
                },
                "position": [0, 12, 12, 6]
              },
              {
                "type": "log",
                "properties": {
                  "title": "Top 10 Destination IPs by Rejected Connections",
                  "logGroupNames": [ "${LogGroupName}" ],
                  "view": "table",
                  "timeRange": {
                    "Relative": "P7D"
                  },
                  "region": "${AWS::Region}",
                  "query": {
                    "SourceId": "1",
                    "QueryString": "filter interfaceId like /eni-/ and action = \"REJECT\" | stats count() as rejects by bin(1h), dstAddr | sort rejects desc | limit 10"
                  }
                },
                "position": [12, 12, 12, 6]
              }
            ]
          }

Outputs:
  DashboardArn:
    Description: ARN of the CloudWatch Dashboard
    Value: !Sub 'arn:${AWS::Partition}:cloudwatch:${AWS::Region}:${AWS::AccountId}:dashboard/${DashboardName}'

AWSTemplateFormatVersion: '2010-09-09'
Description: Secure static website hosted on S3 with CloudFront CDN integration, automated content deployment and cleanup using Lambda-backed Custom Resource.

Resources:
  S3Bucket:
    Type: AWS::S3::Bucket
    Properties:
      BucketName: !Sub "${AWS::StackName}-us-east-1-${AWS::AccountId}-static-site"
      PublicAccessBlockConfiguration:
        BlockPublicAcls: true
        BlockPublicPolicy: true
        IgnorePublicAcls: true
        RestrictPublicBuckets: true
      BucketEncryption:
        ServerSideEncryptionConfiguration:
          - ServerSideEncryptionByDefault:
              SSEAlgorithm: AES256
      VersioningConfiguration:
        Status: Suspended
      WebsiteConfiguration:
        IndexDocument: index.html
        ErrorDocument: error.html

  CloudFrontDistribution:
    Type: AWS::CloudFront::Distribution
    Properties:
      DistributionConfig:
        Origins:
          - Id: S3Origin
            DomainName: !Sub "${S3Bucket}.s3.amazonaws.com"
        DefaultCacheBehavior:
          TargetOriginId: S3Origin
          ViewerProtocolPolicy: redirect-to-https
          AllowedMethods:
            - GET
            - HEAD
            - OPTIONS
          CachedMethods:
            - GET
            - HEAD
          ForwardedValues:
            QueryString: false
            Cookies:
              Forward: none
          MinTTL: 0
          DefaultTTL: 0
          MaxTTL: 0
        DefaultRootObject: index.html
        CustomErrorResponses:
          - ErrorCode: 403
            ResponseCode: 200
            ResponsePagePath: /index.html
          - ErrorCode: 404
            ResponseCode: 200
            ResponsePagePath: /index.html
        Comment: Secure static website distribution with caching disabled
        PriceClass: PriceClass_100
        Enabled: true

  BucketPolicy:
    Type: AWS::S3::BucketPolicy
    Properties:
      Bucket: !Ref S3Bucket
      PolicyDocument:
        Statement:
          - Effect: Allow
            Principal:
              Service: cloudfront.amazonaws.com
            Action: s3:GetObject
            Resource: !Sub "arn:aws:s3:::${S3Bucket}/*"
            Condition:
              StringEquals:
                "AWS:SourceArn": !Sub "arn:aws:cloudfront::${AWS::AccountId}:distribution/${CloudFrontDistribution}"

  LambdaRole:
    Type: AWS::IAM::Role
    Properties:
      AssumeRolePolicyDocument:
        Version: '2012-10-17'
        Statement:
          - Effect: Allow
            Principal:
              Service: lambda.amazonaws.com
            Action: sts:AssumeRole
      ManagedPolicyArns:
        - arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole
      Policies:
        - PolicyName: S3BucketAccess
          PolicyDocument:
            Version: '2012-10-17'
            Statement:
              - Effect: Allow
                Action:
                  - s3:ListBucket
                Resource: !GetAtt S3Bucket.Arn
              - Effect: Allow
                Action:
                  - s3:PutObject
                  - s3:GetObject
                  - s3:DeleteObject
                Resource: !Sub "arn:aws:s3:::${S3Bucket}/*"

  LambdaFunction:
    Type: AWS::Lambda::Function
    Properties:
      Handler: index.handler
      Role: !GetAtt LambdaRole.Arn
      Runtime: nodejs20.x
      Timeout: 60
      Environment:
        Variables:
          Region: !Ref AWS::Region
      Code:
        ZipFile: |
          const https = require('https');
          const http = require('http');
          const url = require('url');
          const aws = require('aws-sdk');
          const s3 = new aws.S3({ apiVersion: '2006-03-01' });

          function sendResponse(event, context, responseStatus, responseData, physicalResourceId) {
            const responseBody = JSON.stringify({
              Status: responseStatus,
              Reason: `See the details in CloudWatch Log Stream: ${context.logStreamName}`,
              PhysicalResourceId: physicalResourceId || context.logStreamName,
              StackId: event.StackId,
              RequestId: event.RequestId,
              LogicalResourceId: event.LogicalResourceId,
              Data: responseData,
            });

            const parsedUrl = url.parse(event.ResponseURL);
            let requestModule = parsedUrl.protocol === 'https:' ? https : http;
            const options = {
              hostname: parsedUrl.hostname,
              port: parsedUrl.port || (parsedUrl.protocol === 'https:' ? 443 : 80),
              path: parsedUrl.path,
              method: 'PUT',
              headers: {
                'content-type': '',
                'content-length': Buffer.byteLength(responseBody),
              },
            };

            return new Promise((resolve, reject) => {
              const request = requestModule.request(options, (response) => {
                if (response.statusCode < 200 || response.statusCode >= 300) {
                  reject(new Error(`Bad statusCode: ${response.statusCode}`));
                } else {
                  resolve('SUCCESS');
                }
              });
              request.on('error', reject);
              request.write(responseBody);
              request.end();
            });
          }

          exports.handler = async (event, context) => {
            const physicalResourceId = event.PhysicalResourceId || 'PopulateS3Content';
            const responseData = {};
            try {
              const bucketName = event.ResourceProperties.BucketName;
              if (event.RequestType === 'Delete') {
                let continuationToken;
                do {
                  const listParams = {
                    Bucket: bucketName,
                  };
                  if (continuationToken) {
                    listParams.ContinuationToken = continuationToken;
                  }
                  const objects = await s3.listObjectsV2(listParams).promise();
                  if (objects.Contents && objects.Contents.length > 0) {
                    const deleteParams = {
                      Bucket: bucketName,
                      Delete: {
                        Objects: objects.Contents.map(o => ({ Key: o.Key })),
                      },
                    };
                    await s3.deleteObjects(deleteParams).promise();
                  }
                  continuationToken = objects.NextContinuationToken;
                } while (continuationToken);
                await sendResponse(event, context, 'SUCCESS', responseData, physicalResourceId);
              } else if (event.RequestType === 'Create') {
                const html = `<html><head><title>Hello World</title></head><body><h1>Hello World from S3 + CloudFront!</h1></body></html>`;
                await s3.putObject({
                  Bucket: bucketName,
                  Key: 'index.html',
                  Body: html,
                  ContentType: 'text/html',
                }).promise();
                await sendResponse(event, context, 'SUCCESS', responseData, physicalResourceId);
              } else {
                await sendResponse(event, context, 'SUCCESS', responseData, physicalResourceId);
              }
            } catch (err) {
              console.error(err);
              await sendResponse(event, context, 'FAILED', { Error: err.message }, physicalResourceId);
            }
          };

  PopulateS3Content:
    Type: AWS::CloudFormation::CustomResource
    DeletionPolicy: Delete
    Properties:
      ServiceToken: !GetAtt LambdaFunction.Arn
      BucketName: !Ref S3Bucket

Outputs:
  CloudFrontDomainName:
    Description: CloudFront Distribution Domain Name
    Value: !GetAtt CloudFrontDistribution.DomainName
    Export:
      Name: !Sub "${AWS::StackName}-CloudFrontDomain"

  S3BucketName:
    Description: S3 Bucket Name
    Value: !Ref S3Bucket
    Export:
      Name: !Sub "${AWS::StackName}-S3BucketName"

AWSTemplateFormatVersion: '2010-09-09'
Description: 'Secure static website hosted on S3 with CloudFront CDN using Origin Access Control (OAC), custom cache policy for 60s TTL and HTTPS enforcement, and Lambda Custom Resource for automated content management (default index.html upload on create, bucket empty on delete).'

Parameters:
  IndexFileContent:
    Type: String
    Default: |
      <!DOCTYPE html>
      <html>
      <head>
        <title>Secure Static Site</title>
      </head>
      <body>
        <h1>Hello World from Secure S3 + CloudFront OAC!</h1>
        <p>This site is served via private S3 bucket with CloudFront Origin Access Control.</p>
      </body>
      </html>
    Description: 'HTML content for the default index.html file.'

Resources:
  StaticWebsiteBucket:
    Type: AWS::S3::Bucket
    Properties:
      BucketName: !Sub "${AWS::StackName}-${AWS::Region}-${AWS::AccountId}-static-site-bucket"
      BucketEncryption:
        ServerSideEncryptionConfiguration:
          - ServerSideEncryptionByDefault:
              SSEAlgorithm: aws:kms
      VersioningConfiguration:
        Status: Enabled
      PublicAccessBlockConfiguration:
        BlockPublicAcls: true
        BlockPublicPolicy: true
        IgnorePublicAcls: true
        RestrictPublicBuckets: true
      Tags:
        - Key: Name
          Value: !Sub "${AWS::StackName}-bucket"

  OriginAccessControl:
    Type: AWS::CloudFront::OriginAccessControl
    Properties:
      OriginAccessControlConfig:
        Name: !Sub "${AWS::StackName}-oac"
        OriginAccessControlOriginType: s3
        SigningBehavior: always
        SigningProtocol: sigv4

  CustomCachePolicy:
    Type: AWS::CloudFront::CachePolicy
    Properties:
      CachePolicyConfig:
        Name: !Sub "${AWS::StackName}-cache-policy"
        Comment: 'Custom cache policy: 60s default TTL, optimized for static content'
        MinTTL: 0
        DefaultTTL: 60
        MaxTTL: 31536000
        ParametersInCacheKeyAndForwardedToOrigin:
          EnableAcceptEncodingGzip: true
          CookiesConfig:
            CookieBehavior: none
          HeadersConfig:
            HeaderBehavior: none
          QueryStringsConfig:
            QueryStringBehavior: none

  CloudFrontDistribution:
    Type: AWS::CloudFront::Distribution
    Properties:
      DistributionConfig:
        Comment: !Sub "${AWS::StackName} secure static site distribution"
        Enabled: true
        PriceClass: PriceClass_100
        DefaultRootObject: index.html
        DefaultCacheBehavior:
          TargetOriginId: S3Origin
          CachePolicyId: !Ref CustomCachePolicy
          ViewerProtocolPolicy: redirect-to-https
          AllowedMethods:
            - GET
            - HEAD
            - OPTIONS
          CachedMethods:
            - GET
            - HEAD
        Origins:
          - Id: S3Origin
            DomainName: !Sub "${StaticWebsiteBucket}.s3.${AWS::Region}.amazonaws.com"
            OriginAccessControlId: !Ref OriginAccessControl
      Tags:
        - Key: Name
          Value: !Ref AWS::StackName

  StaticWebsiteBucketPolicy:
    Type: AWS::S3::BucketPolicy
    Properties:
      Bucket: !Ref StaticWebsiteBucket
      PolicyDocument:
        Version: '2012-10-17'
        Statement:
          - Effect: Allow
            Principal:
              AWS: !Sub "arn:aws:cloudfront::${AWS::AccountId}:distribution/${CloudFrontDistribution}"
            Action: s3:GetObject
            Resource: !Sub "arn:aws:s3:::${StaticWebsiteBucket}/*"
            Condition:
              StringEquals:
                aws:SourceArn: !Sub "arn:aws:cloudfront::${AWS::AccountId}:distribution/${CloudFrontDistribution}"

  S3ContentManagerRole:
    Type: AWS::IAM::Role
    Properties:
      AssumeRolePolicyDocument:
        Version: '2012-10-17'
        Statement:
          - Effect: Allow
            Principal:
              Service: lambda.amazonaws.com
            Action: sts:AssumeRole
      ManagedPolicyArns:
        - arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole
      Policies:
        - PolicyName: S3AccessPolicy
          PolicyDocument:
            Version: '2012-10-17'
            Statement:
              - Effect: Allow
                Action:
                  - s3:ListBucket
                Resource: !GetAtt StaticWebsiteBucket.Arn
              - Effect: Allow
                Action:
                  - s3:PutObject
                  - s3:DeleteObject
                  - s3:DeleteObjectVersion
                Resource: !Sub "arn:aws:s3:::${StaticWebsiteBucket}/*"
      Tags:
        - Key: Name
          Value: !Sub "${AWS::StackName}-content-manager-role"

  S3ContentManagerLambda:
    Type: AWS::Lambda::Function
    Properties:
      FunctionName: !Sub "${AWS::StackName}-S3ContentManager"
      Handler: index.handler
      Role: !GetAtt S3ContentManagerRole.Arn
      Runtime: nodejs20.x
      Timeout: 60
      MemorySize: 128
      Code:
        ZipFile: |
          const https = require('https');
          const urlParse = require('url').parse;
          const { S3Client, PutObjectCommand, ListObjectVersionsCommand, DeleteObjectsCommand } = require("@aws-sdk/client-s3");

          function sendResponse(event, status, data = {}, reason = null) {
            const responseBody = JSON.stringify({
              Status: status,
              Reason: reason || `See CloudWatch logs for ${event.PhysicalResourceId}`,
              PhysicalResourceId: event.PhysicalResourceId || data.PhysicalResourceId || (Date.now().toString()),
              StackId: event.StackId,
              RequestId: event.RequestId,
              LogicalResourceId: event.LogicalResourceId,
              Data: data
            });

            const parsedUrl = urlParse(event.ResponseURL);
            const options = {
              hostname: parsedUrl.hostname,
              port: 443,
              path: parsedUrl.path,
              method: 'PUT',
              headers: {
                'Content-Type': '',
                'Content-Length': Buffer.byteLength(responseBody)
              }
            };

            return new Promise((resolve, reject) => {
              const request = https.request(options, (response) => {
                let body = '';
                response.on('data', (chunk) => { body += chunk; });
                response.on('end', () => {
                  if (response.statusCode >= 200 && response.statusCode < 300) {
                    resolve({ body });
                  } else {
                    reject(new Error(`Response code: ${response.statusCode}, body: ${body}`));
                  }
                });
              });

              request.on('error', reject);
              request.write(responseBody);
              request.end();
            });
          }

          exports.handler = async (event) => {
            const s3 = new S3Client({});
            const bucket = event.ResourceProperties.BucketName;
            const content = event.ResourceProperties.IndexFileContent;
            const physicalResourceId = event.PhysicalResourceId || (Date.now().toString());
            const responseData = { BucketInitialized: true };

            try {
              if (event.RequestType === 'Delete') {
                // Empty bucket including all versions and delete markers
                let continuationToken;
                let objectsToDelete = [];

                do {
                  const listParams = { Bucket: bucket };
                  if (continuationToken) {
                    listParams.ContinuationToken = continuationToken;
                  }
                  const listResp = await s3.send(new ListObjectVersionsCommand(listParams));
                  if (listResp.Versions) {
                    objectsToDelete.push(...listResp.Versions.map(v => ({ Key: v.Key, VersionId: v.VersionId })));
                  }
                  if (listResp.DeleteMarkers) {
                    objectsToDelete.push(...listResp.DeleteMarkers.map(dm => ({ Key: dm.Key, VersionId: dm.VersionId })));
                  }
                  continuationToken = listResp.NextContinuationToken;
                } while (continuationToken);

                // Delete in batches of 1000
                for (let i = 0; i < objectsToDelete.length; i += 1000) {
                  const batch = objectsToDelete.slice(i, i + 1000);
                  await s3.send(new DeleteObjectsCommand({
                    Bucket: bucket,
                    Delete: { Objects: batch, Quiet: true }
                  }));
                }
              } else {
                // Create or Update: upload index.html
                await s3.send(new PutObjectCommand({
                  Bucket: bucket,
                  Key: 'index.html',
                  Body: content,
                  ContentType: 'text/html'
                }));
              }

              await sendResponse(event, 'SUCCESS', responseData);
            } catch (err) {
              console.error(err);
              await sendResponse(event, 'FAILED', {}, err.message || err.toString());
            }
          };
      Tags:
        - Key: Name
          Value: !Sub "${AWS::StackName}-content-manager-lambda"

  LambdaInvokePermission:
    Type: AWS::Lambda::Permission
    Properties:
      FunctionName: !Ref S3ContentManagerLambda
      Action: lambda:InvokeFunction
      Principal: cloudformation.amazonaws.com
      SourceArn: !Sub "arn:aws:cloudformation:${AWS::Region}:${AWS::AccountId}:stack/${AWS::StackName}/*"

  BucketInitialization:
    Type: Custom::S3ContentManager
    Properties:
      ServiceToken: !GetAtt S3ContentManagerLambda.Arn
      BucketName: !Ref StaticWebsiteBucket
      IndexFileContent: !Ref IndexFileContent

Outputs:
  CloudFrontDistributionId:
    Description: 'ID of the CloudFront Distribution'
    Value: !Ref CloudFrontDistribution
    Export:
      Name: !Sub "${AWS::StackName}-CloudFrontDistributionId"

  CloudFrontDomainName:
    Description: 'Domain name of the CloudFront Distribution (e.g., d1234567890abcdef.cloudfront.net)'
    Value: !GetAtt CloudFrontDistribution.DomainName
    Export:
      Name: !Sub "${AWS::StackName}-CloudFrontDomainName"

  S3BucketName:
    Description: 'Name of the S3 Bucket hosting the static website'
    Value: !Ref StaticWebsiteBucket
    Export:
      Name: !Sub "${AWS::StackName}-S3BucketName"
